<?php
ini_set('display_errors', 1);
ini_set('display_startup_errors', 1);
error_reporting(E_ALL);

function findLaravelRoot($dir, $depth = 0) {
    if ($depth > 3) return null;
    if (!is_dir($dir)) return null;
    if (file_exists($dir . '/artisan') && file_exists($dir . '/bootstrap/app.php')) return $dir;
    $items = @scandir($dir);
    if (!$items) return null;
    foreach ($items as $item) {
        if ($item === '.' || $item === '..') continue;
        $path = $dir . '/' . $item;
        if (is_dir($path)) { $found = findLaravelRoot($path, $depth + 1); if ($found) return $found; }
    }
    return null;
}

$laravelRoot = findLaravelRoot(dirname(__DIR__));
if (!$laravelRoot) $laravelRoot = __DIR__;

try {
    $log = '';
    @mkdir(dirname($laravelRoot . '/app/Http/Controllers/InvoiceController.php'), 0777, true);
    file_put_contents($laravelRoot . '/app/Http/Controllers/InvoiceController.php', base64_decode(''));
    $log .= '✔ Berhasil memperbarui file: app/Http/Controllers/InvoiceController.php\n';
    @mkdir(dirname($laravelRoot . '/resources/views/invoices/invoice_lx310.blade.php'), 0777, true);
    file_put_contents($laravelRoot . '/resources/views/invoices/invoice_lx310.blade.php', base64_decode(''));
    $log .= '✔ Berhasil memperbarui file: resources/views/invoices/invoice_lx310.blade.php\n';
    @mkdir(dirname($laravelRoot . '/resources/views/invoices/excel.blade.php'), 0777, true);
    file_put_contents($laravelRoot . '/resources/views/invoices/excel.blade.php', base64_decode(''));
    $log .= '✔ Berhasil memperbarui file: resources/views/invoices/excel.blade.php\n';
    @mkdir(dirname($laravelRoot . '/resources/views/invoices/show.blade.php'), 0777, true);
    file_put_contents($laravelRoot . '/resources/views/invoices/show.blade.php', base64_decode(''));
    $log .= '✔ Berhasil memperbarui file: resources/views/invoices/show.blade.php\n';
    @mkdir(dirname($laravelRoot . '/routes/web.php'), 0777, true);
    file_put_contents($laravelRoot . '/routes/web.php', base64_decode(''));
    $log .= '✔ Berhasil memperbarui file: routes/web.php\n';

    // Boot Laravel untuk artisan commands
    $artisanLog = '';
    try {
        if (file_exists($laravelRoot . '/vendor/autoload.php') && file_exists($laravelRoot . '/bootstrap/app.php')) {
            require $laravelRoot . '/vendor/autoload.php';
            $app = require_once $laravelRoot . '/bootstrap/app.php';
            $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class);
            
            // 1. Jalankan migrasi database
            try {
                $status = $kernel->handle(
                    $input = new Symfony\Component\Console\Input\StringInput('migrate --force'),
                    $output = new Symfony\Component\Console\Output\BufferedOutput
                );
                $artisanLog .= "=== Database Migration ===\n" . $output->fetch() . "\n";
                $log .= '✔ Database migration selesai\n';
            } catch (\Throwable $eMigrate) {
                $artisanLog .= "=== Database Migration Error ===\n" . $eMigrate->getMessage() . "\n";
                $log .= '⚠ Database migration error\n';
            }
            
            // 2. Bersihkan cache (optimize:clear)
            try {
                $status2 = $kernel->handle(
                    $input2 = new Symfony\Component\Console\Input\StringInput('optimize:clear'),
                    $output2 = new Symfony\Component\Console\Output\BufferedOutput
                );
                $artisanLog .= "=== Cache Clear ===\n" . $output2->fetch() . "\n";
                $log .= '✔ Cache Laravel berhasil dibersihkan\n';
            } catch (\Throwable $eCache) {
                $artisanLog .= "=== Cache Clear Error ===\n" . $eCache->getMessage() . "\n";
            }
            
            // 3. Jalankan optimize untuk reload cache terbaru
            try {
                $status3 = $kernel->handle(
                    $input3 = new Symfony\Component\Console\Input\StringInput('optimize'),
                    $output3 = new Symfony\Component\Console\Output\BufferedOutput
                );
                $artisanLog .= "=== Optimize ===\n" . $output3->fetch() . "\n";
                $log .= '✔ Laravel optimized\n';
            } catch (\Throwable $eOptimize) {
                $artisanLog .= "=== Optimize Error ===\n" . $eOptimize->getMessage() . "\n";
            }
        } else {
            $log .= '⚠ Laravel bootstrap files not found, skip DB sync\n';
        }
    } catch (\Throwable $eDb) {
        $log .= '⚠ DB Sync: ' . $eDb->getMessage() . '\n';
        $artisanLog .= 'Error: ' . $eDb->getMessage() . '\n';
    }

    echo "<div style='font-family:Inter,sans-serif;max-width:640px;margin:60px auto;padding:0 20px;'>";  
    echo "<div style='background:linear-gradient(135deg,#d97706,#f59e0b);border-radius:1.25rem;padding:2rem;color:white;text-align:center;margin-bottom:1.5rem;'>";  
    echo "<div style='font-size:3rem;margin-bottom:0.75rem;'>🖨️</div>";  
    echo "<h1 style='margin:0;font-size:1.5rem;font-weight:900;'>Update Cetak Invoice LX-310 & Export Excel Berhasil!</h1>";  
    echo "<p style='margin:0.5rem 0 0;opacity:0.9;font-size:0.9rem;'>Perbaikan Print Dot Matrix + Export Excel + DB Sync (v60)</p>\n";  
    echo "</div>";  
    echo "<div style='background:white;border:1px solid #e5e7eb;border-radius:1rem;padding:1.5rem;margin-bottom:1.25rem;box-shadow:0 4px 16px rgba(0,0,0,0.06);'>";  
    echo "<h2 style='margin:0 0 1rem;color:#1f2937;font-size:1rem;font-weight:800;'>Log Pembaruan File:</h2>";  
    echo "<pre style='background:#f3f4f6;padding:1rem;border-radius:0.5rem;font-size:0.8rem;line-height:1.6;'>" . htmlspecialchars($log) . "</pre>";  
    if (!empty($artisanLog)) {
        echo "<h2 style='margin:1rem 0 0.5rem;color:#1f2937;font-size:1rem;font-weight:800;'>Log Database & Cache:</h2>";
        echo "<pre style='background:#ecfdf5;padding:1rem;border-radius:0.5rem;font-size:0.75rem;line-height:1.5;border:1px solid #a7f3d0;'>" . htmlspecialchars($artisanLog) . "</pre>";
    }
    echo "<div style='margin-top:1rem;padding:1rem;background:#fef3c7;border:1px solid #fcd34d;border-radius:0.5rem;font-size:0.85rem;color:#92400e;'>";  
    echo "<strong>Perubahan:</strong><br>";  
    echo "• Cetak LX-310: Font lebih besar, border tebal, padding lebar, tanpa background hitam<br>";  
    echo "• Mode Internal/Eksternal di LX-310 (kolom Modal, Keuntungan)<br>";  
    echo "• Export Excel (.xls) baru untuk invoice<br>";  
    echo "• Tombol Export Excel di halaman show invoice<br>";  
    echo "• Database migration + cache clear otomatis";  
    echo "</div>";  
    echo "</div>";  
    echo "<div style='text-align:center;'>";  
    echo "<a href='/invoices' style='display:inline-flex;align-items:center;gap:0.5rem;padding:0.875rem 2rem;background:linear-gradient(135deg,#d97706,#f59e0b);color:white;text-decoration:none;border-radius:0.875rem;font-weight:800;font-size:0.95rem;box-shadow:0 4px 16px rgba(217,119,6,0.35);'>📄 Buka Data Invoice</a>";  
    echo "</div>";  
    echo "</div>";  
} catch (\Exception $e) {
    echo "<h1 style='color:red;'>Error:</h1><pre>" . $e->getMessage() . "</pre>";
}
